import play.api._
import play.api.mvc._
import java.nio.file._
 
class FileController extends Controller {
   def download(filename: String) = Action.async { implicit request =>
     val filePathString =  s"uploads/$filename"; // create your path to the files here, it can be an absolute or a relative one based on project structure   
       Files.readAllLines(filePathString).map{ lines => 
         Ok(lines) 
      }  
     };;// read and send back content of file as string using scala io source fromFile method, also support for nested directories if you want to create directory traversal in url path.    // provide a unique name or id so that request can be identified uniquely when user opens the downloaded files  then convert list into String  
}